select
id, shop_notice_id, file_url, status, is_deleted, create_user, update_user, create_time, update_time
from shop_notice_file

    1 = 1 and is_deleted = 0

        and id = #{id}


        and shop_notice_id = #{shopNoticeId}


        and file_url = #{fileUrl}


        and status = #{status}


        and is_deleted = #{isDeleted}


        and create_user = #{createUser}


        and update_user = #{updateUser}


        and create_time = #{createTime}


        and update_time = #{updateTime}

